INSERT INTO `pm_resource_unit` (`id`, `name`, `region`, `city`, `status`, `cluster_radius_km`, `dispatch_mode`, `strategy_label`, `latest_alarm_title`, `latest_alarm_time`, `alarm_total`, `alarm_critical`, `alarm_major`, `alarm_minor`) VALUES ('RU-001','深圳湾科创园聚合单元','华南区域','深圳','normal',8,'日前基线 + 实时修正','深圳南山与前海相邻工商业屋顶光伏共享同城天气剖面，仅按权重分摊出力。','前海冷站屋顶 C 站采集延迟，连续两个时段偏差超阈。','2026-03-23 14:18:00',2,0,1,1),('RU-002','松山湖智造聚合单元','华南区域','东莞','warning',10,'滚动预测 + 偏差压缩','松山湖制造园区资源共享同一片天气趋势，按容量权重分摊实际出力。','松山湖制造园 B 站在 13:45 后出现预测偏差持续放大。','2026-03-23 14:06:00',4,0,2,2),('RU-003','武汉物流基地聚合单元','华中区域','武汉','fault',14,'偏差压降','武汉物流园与仓储园站点共享天气剖面，但故障站拖低聚合单元可调能力。','武汉物流园 A 站逆变器簇故障，导致资源单元响应不完整。','2026-03-23 14:02:00',6,2,2,2),('RU-004','合肥研发协同聚合单元','华东区域','合肥','maintenance',9,'检修窗口 + 保守基线','合肥研发中心邻近站群共享天气剖面，检修期以保守调度为主。','合肥研发中心 A 站处于检修窗口，可调空间暂时下调。','2026-03-23 13:32:00',2,0,1,1),('RU-005','天津港储能园聚合单元','华北区域','天津','offline',11,'退出调度 + 边界保电','天津港储能园区部分站点因通信中断脱网，当前按离线资源单元独立管理。','天津港储能园 A 站通信中断超过 15 分钟，当前已切换至边界保电模式。','2026-03-23 14:12:00',4,1,2,1),('RU-006','成都西部基地聚合单元','西南区域','成都','normal',13,'日前基线 + 实时优化','成都西部基地相邻园区光伏站群共享天气建模，当前可稳定提供上下调能力。','成都仓储园 C 站传感器上报偶发延迟，已自动补采。','2026-03-23 13:26:00',1,0,0,1);
